import React from 'react';
import { useTranslation } from 'react-i18next';

function LanguageSwitcher() {
  const { i18n } = useTranslation();

  const changeLanguage = (lng) => {
    i18n.changeLanguage(lng);
    localStorage.setItem('language', lng);
  };

  return (
    <div style={styles.container}>
      <button onClick={() => changeLanguage('ar')} style={{ ...styles.btn, background: i18n.language === 'ar' ? '#006233' : '#eee', color: i18n.language === 'ar' ? 'white' : '#333' }}>🇩🇿 العربية</button>
      <button onClick={() => changeLanguage('fr')} style={{ ...styles.btn, background: i18n.language === 'fr' ? '#FF69B4' : '#eee', color: i18n.language === 'fr' ? 'white' : '#333' }}>🇫🇷 Français</button>
      <button onClick={() => changeLanguage('en')} style={{ ...styles.btn, background: i18n.language === 'en' ? '#4A90D9' : '#eee', color: i18n.language === 'en' ? 'white' : '#333' }}>🇬🇧 English</button>
    </div>
  );
}

const styles = {
  container: { display: 'flex', gap: '8px', justifyContent: 'center', marginBottom: '15px', flexWrap: 'wrap' },
  btn: { padding: '8px 16px', borderRadius: '20px', border: 'none', fontSize: '0.85rem', fontWeight: 'bold', cursor: 'pointer', transition: 'all 0.3s' },
};

export default LanguageSwitcher;
